// Извлечение и форматирование ответа от Gemini
const items = $input.all();
const output = [];

for (const item of items) {
  let analysisData;
  let rawResponse = '';

  try {
    // Получаем ответ от Gemini
    const geminiResponse = item.json;

    // Извлекаем текст из структуры ответа Gemini
    if (geminiResponse.candidates && geminiResponse.candidates[0]) {
      const candidate = geminiResponse.candidates[0];
      if (candidate.content && candidate.content.parts && candidate.content.parts[0]) {
        rawResponse = candidate.content.parts[0].text;
      }
    }

    // Очищаем от markdown разметки если есть
    rawResponse = rawResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

    // Парсим JSON
    analysisData = JSON.parse(rawResponse);

  } catch (error) {
    // Если парсинг не удался, создаем базовую структуру
    analysisData = {
      document_info: {
        title: "Ошибка парсинга ответа",
        document_type: "error",
        page_count: 0,
        language: "unknown"
      },
      summary: {
        brief: "Не удалось обработать документ",
        detailed: error.message,
        key_points: []
      },
      extracted_data: {
        entities: {
          persons: [],
          organizations: [],
          locations: [],
          dates: []
        }
      },
      metadata: {
        error: error.message,
        raw_response: rawResponse.substring(0, 500)
      }
    };
  }

  // Добавляем метаданные обработки
  if (!analysisData.metadata) {
    analysisData.metadata = {};
  }

  analysisData.metadata.processed_at = new Date().toISOString();
  analysisData.metadata.file_name = item.json.fileName || 'unknown';
  analysisData.metadata.model_used = 'gemini-2.5-flash';

  // Создаем форматированное HTML сообщение для Matrix
  const htmlMessage = `
<h2>📄 Анализ документа завершен</h2>

<h3>📋 Информация о документе</h3>
<ul>
<li><b>Название:</b> ${analysisData.document_info?.title || 'N/A'}</li>
<li><b>Тип:</b> ${analysisData.document_info?.document_type || 'N/A'}</li>
<li><b>Страниц:</b> ${analysisData.document_info?.page_count || 'N/A'}</li>
<li><b>Язык:</b> ${analysisData.document_info?.language || 'N/A'}</li>
</ul>

<h3>📝 Резюме</h3>
<p><i>${analysisData.summary?.brief || 'Резюме недоступно'}</i></p>

<h3>🔑 Ключевые пункты</h3>
<ul>
${(analysisData.summary?.key_points || []).map(point => `<li>${point}</li>`).join('\n')}
</ul>

${analysisData.extracted_data?.entities ? `
<h3>👥 Извлеченные сущности</h3>
<ul>
${analysisData.extracted_data.entities.persons?.length > 0 ? `<li><b>Люди:</b> ${analysisData.extracted_data.entities.persons.join(', ')}</li>` : ''}
${analysisData.extracted_data.entities.organizations?.length > 0 ? `<li><b>Организации:</b> ${analysisData.extracted_data.entities.organizations.join(', ')}</li>` : ''}
${analysisData.extracted_data.entities.locations?.length > 0 ? `<li><b>Места:</b> ${analysisData.extracted_data.entities.locations.join(', ')}</li>` : ''}
</ul>
` : ''}

${analysisData.analysis ? `
<h3>📊 Анализ</h3>
<ul>
<li><b>Настроение:</b> ${analysisData.analysis.sentiment || 'N/A'}</li>
${analysisData.analysis.topics?.length > 0 ? `<li><b>Темы:</b> ${analysisData.analysis.topics.join(', ')}</li>` : ''}
</ul>
` : ''}

<details>
<summary><b>🔍 Полный JSON (нажмите для раскрытия)</b></summary>
<pre><code>${JSON.stringify(analysisData, null, 2)}</code></pre>
</details>

<hr>
<small>Обработано: ${analysisData.metadata.processed_at}</small>
`;

  // Создаем plain text версию
  const plainTextMessage = `
📄 Анализ документа завершен

📋 Информация:
Название: ${analysisData.document_info?.title || 'N/A'}
Тип: ${analysisData.document_info?.document_type || 'N/A'}
Страниц: ${analysisData.document_info?.page_count || 'N/A'}

📝 Резюме:
${analysisData.summary?.brief || 'Резюме недоступно'}

🔑 Ключевые пункты:
${(analysisData.summary?.key_points || []).map((point, i) => `${i+1}. ${point}`).join('\n')}

---
Обработано: ${analysisData.metadata.processed_at}
`;

  output.push({
    json: {
      analysisData: analysisData,
      htmlMessage: htmlMessage,
      plainTextMessage: plainTextMessage,
      fileName: item.json.fileName || 'unknown'
    }
  });
}

return output;
